'use client';
import { useContext } from 'react';
import AsidemenuContext from '@/contexts/asidemenuContext';

export default function AsidemenuProvider({
  children
}: {
  children: React.ReactNode;
}) {
  const { isOpen, setIsOpen } = useAsidemenu();
  return (
    <AsidemenuContext.Provider value={{ isOpen, setIsOpen }}>
      {children}
    </AsidemenuContext.Provider>
  );
}

const useAsidemenu = () => {
  const context = useContext(AsidemenuContext);
  if (!context) {
    throw new Error('useAsidemenu must be used within an AsidemenuProvider');
  }
  return context;
};
